mapper.select:
SELECT *
FROM expense
WHERE user_id = #{userId}
AND account_number = #{accountNumber}
AND transacted_at BETWEEN #{startTime} AND #{endTime}

    AND (transacted_at < #{lastTimestamp} 
        OR (transacted_at = #{lastTimestamp} AND id < #{lastId}))

ORDER BY transacted_at DESC, id DESC

    LIMIT #{size}

